| MCP:TNZd7l | import { defineConfig } from 'vite';
| MCP:TNZd7l | import react  from '@vitejs/plugin-react';
| MCP:TNZd7l | import * as path from 'path';
| MCP:TNZd7l | import { existsSync } from 'fs';
| MCP:TNZd7l | import * as dotenv from 'dotenv';
| MCP:TNZd7l | 
| MCP:TNZd7l | // Dotenv 是一个零依赖的模块，它能将环境变量中的变量从 .env 文件加载到 process.env 中
| MCP:TNZd7l | dotenv.config({
| MCP:TNZd7l |     path: existsSync('.env') ? '.env' : path.resolve('envs', `.env.${process.env.NODE_ENV}`)
| MCP:TNZd7l | });
| MCP:TNZd7l | 
| MCP:TNZd7l | // https://vitejs.dev/config/
| MCP:TNZd7l | export default defineConfig({
| MCP:TNZd7l |     plugins: [react()],
| MCP:TNZd7l |     resolve: {
| MCP:TNZd7l |         alias: {
| MCP:TNZd7l |             '@@': path.resolve(__dirname),
| MCP:TNZd7l |             '@': path.resolve(__dirname, 'src')
| MCP:TNZd7l |         }
| MCP:TNZd7l |     },
| MCP:TNZd7l |     server: {
| MCP:TNZd7l |         cors: true,
| MCP:TNZd7l |         port: process.env.VITE_PORT as unknown as number,
| MCP:TNZd7l |         hmr: {
| MCP:TNZd7l |             host: 'localhost',
| MCP:TNZd7l |             protocol: 'ws',
| MCP:TNZd7l |             port: process.env.VITE_PORT as unknown as number
| MCP:TNZd7l |         }
| MCP:TNZd7l |     }
| MCP:TNZd7l | });

| MCP:TNZd7l | server {
| MCP:TNZd7l |     gzip on;
| MCP:TNZd7l |     listen       80;
| MCP:TNZd7l |     listen  [::]:80;
| MCP:TNZd7l |     server_name  localhost;
| MCP:TNZd7l | 
| MCP:TNZd7l |     location / {
| MCP:TNZd7l |     root /usr/share/nginx/html;
| MCP:TNZd7l |     index  index.html index.htm;
| MCP:TNZd7l |     try_files $uri $uri/ /index.html;
| MCP:TNZd7l |     }
| MCP:TNZd7l | 
| MCP:TNZd7l |     location /admin {
| MCP:TNZd7l |         alias /usr/share/nginx/html/admin;
| MCP:TNZd7l |         index index.html index.htm;
| MCP:TNZd7l |         try_files $uri $uri/ /admin/index.html;
| MCP:TNZd7l |     }
| MCP:TNZd7l | 
| MCP:TNZd7l |     location @rewrites {
| MCP:TNZd7l |         rewrite ^(.*)$ /index.html last;
| MCP:TNZd7l |     }
| MCP:TNZd7l | }
